+<!DOCTYPE html>
+<html>
+<head>
+  <meta charset="utf-8">
+  <meta name="viewport" content="width=device-width, initial-scale=1">
+  <title>drawmode — Excalidraw Viewer</title>
+  <style>
+    * { margin: 0; padding: 0; box-sizing: border-box; }
+    html, body, #root { width: 100%; height: 100%; overflow: hidden; }
+    #loading { display: flex; align-items: center; justify-content: center; height: 100%; font-family: sans-serif; color: #666; }
+  </style>
+</head>
+<body>
+  <div id="root"><div id="loading">Loading Excalidraw…</div></div>
+
+  <script src="https://unpkg.com/react@18/umd/react.production.min.js"></script>
+  <script src="https://unpkg.com/react-dom@18/umd/react-dom.production.min.js"></script>
+  <script src="https://unpkg.com/@excalidraw/excalidraw/dist/excalidraw.production.min.js"></script>
+
+  <script>
+    // Wait for Excalidraw elements via postMessage from the MCP client
+    let excalidrawAPI = null;
+
+    function renderExcalidraw(elements, appState) {
+      const root = document.getElementById("root");
+      root.innerHTML = "";
+
+      const App = React.createElement(
+        ExcalidrawLib.Excalidraw,
+        {
+          initialData: {
+            elements: elements || [],
+            appState: {
+              viewBackgroundColor: "#ffffff",
+              ...appState,
+            },
+          },
+          excalidrawAPI: (api) => { excalidrawAPI = api; },
+          UIOptions: {
+            canvasActions: {
+              export: { saveFileToDisk: true },
+            },
+          },
+        }
+      );
+
+      ReactDOM.createRoot(root).render(App);
+    }
+
+    // Listen for element data from the host
+    window.addEventListener("message", (event) => {
+      const data = event.data;
+      if (!data) return;
+
+      if (data.type === "excalidraw-elements" || data.elements) {
+        const elements = data.elements || data;
+        const appState = data.appState || {};
+        renderExcalidraw(Array.isArray(elements) ? elements : [], appState);
+      }
+
+      // Support updating existing scene
+      if (data.type === "update-scene" && excalidrawAPI) {
+        excalidrawAPI.updateScene({ elements: data.elements });
+      }
+    });
+
+    // Also check for elements embedded in the URL hash
+    try {
+      const hash = window.location.hash.slice(1);
+      if (hash) {
+        const decoded = JSON.parse(decodeURIComponent(hash));
+        if (decoded.elements) {
+          renderExcalidraw(decoded.elements, decoded.appState);
+        }
+      }
+    } catch {
+      // no embedded data
+    }
+  </script>
+</body>
+</html>

